arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now respects the UTF-8 flag,
        // which breaks legacy consumers expecting Shift-JIS encoded filenames.
        // Pin encoding to Shift-JIS so the Java system can read the entries.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices] no longer falls back to
// non-keyed registrations; it throws InvalidOperationException instead.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

